var ActivityTelemetryClient = class extends TelemetryClient {
  trackCliSubcommandLs(v) {
    if (v) {
      this.trackCliSubcommand({
        subcommand: "ls",
        value: v
      });
    }
  }
  trackCliSubcommandTypes(v) {
    if (v) {
      this.trackCliSubcommand({
        subcommand: "types",
        value: v
      });
    }
  }
  trackCliOptionType(v) {
    if (v && v.length > 0) {
      this.trackCliOption({
        option: "type",
        value: v.join(",")
      });
    }
  }
  trackCliOptionSince(v) {
    if (v) {
      this.trackCliOption({
        option: "since",
        value: this.redactedValue
      });
    }
  }
  trackCliOptionUntil(v) {
    if (v) {
      this.trackCliOption({
        option: "until",
        value: this.redactedValue
      });
    }
  }
  trackCliOptionProject(v) {
    if (v) {
      this.trackCliOption({
        option: "project",
        value: this.redactedValue
      });
    }
  }
  trackCliFlagAll(v) {
    if (v) {
      this.trackCliFlag("all");
    }
  }
  trackCliOptionLimit(v) {
    if (typeof v === "number") {
      this.trackCliOption({
        option: "limit",
        value: this.redactedValue
      });
    }
  }
  trackCliOptionNext(v) {
    if (typeof v === "number") {
      this.trackCliOption({
        option: "next",
        value: this.redactedValue
      });
    }
  }
};

