// src/commands/mcp/constants.ts
var MCP_CLIENTS = [
  { slug: "claude-code", display: "Claude Code" },
  { slug: "claude-desktop", display: "Claude.ai and Claude for desktop" },
  { slug: "cursor", display: "Cursor" },
  { slug: "vscode-copilot", display: "VS Code with Copilot" }
];
var MCP_CLIENT_DISPLAY_NAMES = MCP_CLIENTS.map((c) => c.display);

// src/commands/mcp/index.ts
function buildSuggestedMcpCommand(client, clientsValue) {
  const args = client.argv.slice(2);
  const preserved = [];
  let hasNonInteractive = false;
  for (let i = 1; i < args.length; i++) {
    const arg = args[i];
    if (arg === "--non-interactive") {
      hasNonInteractive = true;
      continue;
    }
    if (arg === "--clients") {
      i++;
      while (i < args.length && !args[i].startsWith("-")) {
        i++;
      }
      i--;
      continue;
    }
    if (arg.startsWith("--clients=")) {
      continue;
    }
    preserved.push(arg);
  }
  const singleQuotedClients = `'${clientsValue}'`;
  preserved.push("--clients", singleQuotedClients);
  if (hasNonInteractive) {
    preserved.push("--non-interactive");
  }
  const suffix = preserved.join(" ");
  return suffix ? `${packageName} mcp ${suffix}` : `${packageName} mcp`;
}
function parseAndValidateClients(clientsFlag) {
  if (!clientsFlag || !clientsFlag.trim())
    return [];
  const requested = clientsFlag.split(",").map((s) => s.trim()).filter(Boolean);
  const normalized = requested.map((name) => {
    const lower = name.toLowerCase();
    const match = MCP_CLIENT_DISPLAY_NAMES.find((c) => c.toLowerCase() === lower);
    return match ?? name;
  });
  return [...new Set(normalized)];
}
async function main22(client) {
  let parsedArgs;
  const flagsSpecification = getFlagsSpecification(mcpCommand.options);
  try {
    parsedArgs = parseArguments(client.argv.slice(2), flagsSpecification);
  } catch (error) {
    printError(error);
    return 1;
  }
  if (parsedArgs.flags["--help"]) {
    output_manager_default.print(help(mcpCommand, { columns: client.stderr.columns }));
    return 2;
  }
  const project = !!parsedArgs.flags["--project"];
  const clientsFlag = parsedArgs.flags["--clients"];
  const clients = parseAndValidateClients(clientsFlag);
  if (client.nonInteractive) {
    if (clients.length === 0) {
      outputAgentError(
        client,
        {
          status: "error",
          reason: "missing_clients",
          message: "In non-interactive mode --clients is required. Specify a comma-separated list of MCP clients to set up.",
          next: [
            {
              command: buildSuggestedMcpCommand(
                client,
                "Cursor,VS Code with Copilot"
              )
            }
          ]
        },
        1
      );
      return 1;
    }
    const invalid = clients.filter(
      (c) => !MCP_CLIENT_DISPLAY_NAMES.some((v) => v === c)
    );
    if (invalid.length > 0) {
      outputAgentError(
        client,
        {
          status: "error",
          reason: "invalid_clients",
          message: `Invalid client(s): ${invalid.join(
            ", "
          )}. Valid options: ${MCP_CLIENT_DISPLAY_NAMES.join(", ")}.`,
          next: [
            {
              command: buildSuggestedMcpCommand(
                client,
                "Cursor,VS Code with Copilot"
              )
            }
          ]
        },
        1
      );
      return 1;
    }
  }
  if (project) {
    client.argv.push("--project");
  }
  try {
    return await mcp(client, { project, clients });
  } catch (err) {
    output_manager_default.prettyError(err);
    return 1;
  }
}

