// src/util/teams/create-team.ts
async function createTeam(client, { slug }, opts) {
  const fetchOpts = {
    method: "POST",
    body: { slug },
    useCurrentTeam: false,
    bailOn429: true
  };
  if (opts?.signal) {
    fetchOpts.signal = opts.signal;
  }
  const body = await client.fetch(`/teams`, fetchOpts);
  return body;
}

// src/util/teams/patch-team.ts
async function patchTeam(client, teamId, payload) {
  const body = await client.fetch(
    `/teams/${encodeURIComponent(teamId)}`,
    {
      method: "PATCH",
      body: payload
    }
  );
  if (body && typeof body === "object" && "ok" in body) {
    throw new Error("PATCH /teams returned non-JSON response");
  }
  return body;
}

